import{_ as a,o as r,c as i,ag as t}from"./chunks/framework.gU7RhlGX.js";const g=JSON.parse('{"title":"一张大白话对比表","description":"","frontmatter":{},"headers":[],"relativePath":"工具/CLI-Anything 和 Open Interpreter 的区别.md","filePath":"工具/CLI-Anything 和 Open Interpreter 的区别.md","lastUpdated":1776422487000}'),n={name:"工具/CLI-Anything 和 Open Interpreter 的区别.md"};function l(h,e,o,s,p,d){return r(),i("div",null,[...e[0]||(e[0]=[t(`<p>行，我直接用大白话给你对比。</p><p>先一句话总结：</p><ul><li><strong>CLI-Anything</strong>：给软件“做接口”</li><li><strong>MCP</strong>：给模型“接工具”</li><li><strong>browser-use</strong>：让 AI“操作网页”</li><li><strong>Open Interpreter</strong>：让 AI“直接用电脑/终端干活”</li></ul><p>它们不是完全同类，有些是上下游关系。</p><hr><h1 id="一张大白话对比表" tabindex="-1">一张大白话对比表 <a class="header-anchor" href="#一张大白话对比表" aria-label="Permalink to &quot;一张大白话对比表&quot;">​</a></h1><table tabindex="0"><thead><tr><th>东西</th><th>它本质上是啥</th><th>主要干嘛</th><th>最擅长</th><th>最大短板</th></tr></thead><tbody><tr><td><strong>CLI-Anything</strong></td><td>软件接口生成器</td><td>把 GUI/现有软件变成 CLI 工具</td><td>给复杂软件做稳定、结构化命令接口</td><td>不是啥软件都好改，构建成本高</td></tr><tr><td><strong>MCP</strong></td><td>工具接入协议</td><td>让模型知道“有哪些工具可用，怎么调用”</td><td>标准化接工具</td><td>它自己不解决工具从哪来</td></tr><tr><td><strong>browser-use</strong></td><td>网页操作代理</td><td>让 AI 在浏览器里点、填、跳转</td><td>处理网站、表单、后台系统</td><td>容易受页面变化影响，稳定性一般</td></tr><tr><td><strong>Open Interpreter</strong></td><td>通用电脑代理</td><td>让 AI 直接跑代码、用 shell、操作本机</td><td>灵活，啥都能试</td><td>太自由，容易乱、脆、不够规范</td></tr></tbody></table><hr><h1 id="_1-cli-anything-和-mcp-的区别" tabindex="-1">1. CLI-Anything 和 MCP 的区别 <a class="header-anchor" href="#_1-cli-anything-和-mcp-的区别" aria-label="Permalink to &quot;1. CLI-Anything 和 MCP 的区别&quot;">​</a></h1><p>这个最容易搞混。</p><h2 id="mcp-是什么" tabindex="-1">MCP 是什么？ <a class="header-anchor" href="#mcp-是什么" aria-label="Permalink to &quot;MCP 是什么？&quot;">​</a></h2><p>你可以把 <strong>MCP</strong> 理解成：</p><p><strong>“AI 和工具之间的插座标准。”</strong></p><p>它解决的问题是：</p><ul><li>模型怎么知道有哪些工具</li><li>每个工具叫什么</li><li>参数是什么</li><li>返回结果长什么样</li></ul><p>也就是说，MCP 更像 <strong>协议 / 接口规范</strong>。</p><hr><h2 id="cli-anything-是什么" tabindex="-1">CLI-Anything 是什么？ <a class="header-anchor" href="#cli-anything-是什么" aria-label="Permalink to &quot;CLI-Anything 是什么？&quot;">​</a></h2><p>CLI-Anything 不是协议，它是在做：</p><p><strong>“把原来不好调用的软件，先做成一个像样的工具。”</strong></p><p>也就是说，CLI-Anything 解决的是：</p><ul><li>工具本身怎么造出来</li><li>怎么把 GIMP / Blender / LibreOffice 变成 AI 能调的命令行工具</li></ul><hr><h2 id="最直白的类比" tabindex="-1">最直白的类比 <a class="header-anchor" href="#最直白的类比" aria-label="Permalink to &quot;最直白的类比&quot;">​</a></h2><h3 id="mcp-插线板标准" tabindex="-1">MCP = 插线板标准 <a class="header-anchor" href="#mcp-插线板标准" aria-label="Permalink to &quot;MCP = 插线板标准&quot;">​</a></h3><p>规定插头怎么插、几孔、多少伏、怎么通电。</p><h3 id="cli-anything-电器改造厂" tabindex="-1">CLI-Anything = 电器改造厂 <a class="header-anchor" href="#cli-anything-电器改造厂" aria-label="Permalink to &quot;CLI-Anything = 电器改造厂&quot;">​</a></h3><p>把原来没法直接插的设备，改造成能接标准插座的设备。</p><hr><h2 id="它们的关系" tabindex="-1">它们的关系 <a class="header-anchor" href="#它们的关系" aria-label="Permalink to &quot;它们的关系&quot;">​</a></h2><p>它们其实不是竞争关系，反而像上下游：</p><ul><li><strong>CLI-Anything 负责造工具</strong></li><li><strong>MCP 负责把工具接给模型</strong></li></ul><p>你甚至可以想象：</p><ul><li>先用 CLI-Anything 造出 <code>cli-anything-gimp</code></li><li>再用 MCP 把这个工具暴露给模型调用</li></ul><p>所以： <strong>CLI-Anything 更偏“工具生产”</strong><strong>MCP 更偏“工具接入标准”</strong></p><hr><h1 id="_2-cli-anything-和-browser-use-的区别" tabindex="-1">2. CLI-Anything 和 browser-use 的区别 <a class="header-anchor" href="#_2-cli-anything-和-browser-use-的区别" aria-label="Permalink to &quot;2. CLI-Anything 和 browser-use 的区别&quot;">​</a></h1><p>这个区别也很大。</p><h2 id="browser-use-是什么" tabindex="-1">browser-use 是什么？ <a class="header-anchor" href="#browser-use-是什么" aria-label="Permalink to &quot;browser-use 是什么？&quot;">​</a></h2><p>一句话：</p><p><strong>让 AI 像人一样操作网页。</strong></p><p>它常干的事是：</p><ul><li>打开网页</li><li>找输入框</li><li>填表单</li><li>点按钮</li><li>翻页</li><li>抓页面内容</li><li>处理网站工作流</li></ul><p>适合场景：</p><ul><li>管理后台</li><li>电商网站</li><li>CRM</li><li>各种没有好 API 的网页系统</li></ul><hr><h2 id="cli-anything-是什么-1" tabindex="-1">CLI-Anything 是什么？ <a class="header-anchor" href="#cli-anything-是什么-1" aria-label="Permalink to &quot;CLI-Anything 是什么？&quot;">​</a></h2><p>CLI-Anything 不是“点网页”，而是：</p><p><strong>尽量绕过 GUI 交互，直接给软件做结构化命令接口。</strong></p><p>它想做的是：</p><ul><li>不靠看页面瞎点</li><li>不靠找按钮位置</li><li>而是直接下命令</li></ul><p>比如不是：</p><ul><li>打开 LibreOffice 窗口</li><li>点插入标题</li><li>点导出 PDF</li></ul><p>而是直接：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cli-anything-libreoffice</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> writer</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add-heading</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cli-anything-libreoffice</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> export</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> render</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> output.pdf</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><hr><h2 id="最直白的类比-1" tabindex="-1">最直白的类比 <a class="header-anchor" href="#最直白的类比-1" aria-label="Permalink to &quot;最直白的类比&quot;">​</a></h2><h3 id="browser-use-让-ai-当-会点网页的实习生" tabindex="-1">browser-use = 让 AI 当“会点网页的实习生” <a class="header-anchor" href="#browser-use-让-ai-当-会点网页的实习生" aria-label="Permalink to &quot;browser-use = 让 AI 当“会点网页的实习生”&quot;">​</a></h3><p>它真的在网站里点来点去。</p><h3 id="cli-anything-给-ai-一个-后台控制面板" tabindex="-1">CLI-Anything = 给 AI 一个“后台控制面板” <a class="header-anchor" href="#cli-anything-给-ai-一个-后台控制面板" aria-label="Permalink to &quot;CLI-Anything = 给 AI 一个“后台控制面板”&quot;">​</a></h3><p>不用去前台点页面，直接从后端正规操作。</p><hr><h2 id="谁更稳" tabindex="-1">谁更稳？ <a class="header-anchor" href="#谁更稳" aria-label="Permalink to &quot;谁更稳？&quot;">​</a></h2><p>一般来说：</p><ul><li><strong>CLI-Anything 更稳</strong></li><li><strong>browser-use 更灵活</strong></li></ul><p>为什么？</p><h3 id="cli-anything-更稳" tabindex="-1">CLI-Anything 更稳 <a class="header-anchor" href="#cli-anything-更稳" aria-label="Permalink to &quot;CLI-Anything 更稳&quot;">​</a></h3><p>因为它是结构化命令，不太怕界面改版。</p><h3 id="browser-use-更灵活" tabindex="-1">browser-use 更灵活 <a class="header-anchor" href="#browser-use-更灵活" aria-label="Permalink to &quot;browser-use 更灵活&quot;">​</a></h3><p>因为网站没 API、没 CLI 时，它还是能干。<br> 只要页面能打开，理论上都能试。</p><hr><h2 id="什么时候该用哪个" tabindex="-1">什么时候该用哪个？ <a class="header-anchor" href="#什么时候该用哪个" aria-label="Permalink to &quot;什么时候该用哪个？&quot;">​</a></h2><h3 id="用-browser-use" tabindex="-1">用 browser-use <a class="header-anchor" href="#用-browser-use" aria-label="Permalink to &quot;用 browser-use&quot;">​</a></h3><ul><li>你面对的是网页系统</li><li>没 API</li><li>只能点页面</li><li>任务偏表单、网页流程</li></ul><h3 id="用-cli-anything" tabindex="-1">用 CLI-Anything <a class="header-anchor" href="#用-cli-anything" aria-label="Permalink to &quot;用 CLI-Anything&quot;">​</a></h3><ul><li>你面对的是软件能力</li><li>想长期稳定自动化</li><li>想让 AI 不依赖截图点按钮</li><li>想做工程化接口</li></ul><hr><h1 id="_3-cli-anything-和-open-interpreter-的区别" tabindex="-1">3. CLI-Anything 和 Open Interpreter 的区别 <a class="header-anchor" href="#_3-cli-anything-和-open-interpreter-的区别" aria-label="Permalink to &quot;3. CLI-Anything 和 Open Interpreter 的区别&quot;">​</a></h1><p>这个区别其实是“规范化程度”不同。</p><h2 id="open-interpreter-是什么" tabindex="-1">Open Interpreter 是什么？ <a class="header-anchor" href="#open-interpreter-是什么" aria-label="Permalink to &quot;Open Interpreter 是什么？&quot;">​</a></h2><p>一句话：</p><p><strong>让 AI 像一个很自由的电脑高手，直接用你的终端和系统。</strong></p><p>它会做的事：</p><ul><li>跑 Python</li><li>跑 shell</li><li>装包</li><li>改文件</li><li>执行脚本</li><li>有时候还会碰 GUI / 本机环境</li></ul><p>它的特点是： <strong>很自由，几乎啥都能试。</strong></p><hr><h2 id="cli-anything-是什么-2" tabindex="-1">CLI-Anything 是什么？ <a class="header-anchor" href="#cli-anything-是什么-2" aria-label="Permalink to &quot;CLI-Anything 是什么？&quot;">​</a></h2><p>CLI-Anything 不是“让 AI 想怎么搞就怎么搞”，而是：</p><p><strong>先把某个软件封装成一套规范工具，再给 AI 用。</strong></p><p>也就是说：</p><ul><li>Open Interpreter 偏“自由发挥”</li><li>CLI-Anything 偏“先造好专业工具再调用”</li></ul><hr><h2 id="最直白的类比-2" tabindex="-1">最直白的类比 <a class="header-anchor" href="#最直白的类比-2" aria-label="Permalink to &quot;最直白的类比&quot;">​</a></h2><h3 id="open-interpreter-一个会自己找办法的全能技术员" tabindex="-1">Open Interpreter = 一个会自己找办法的全能技术员 <a class="header-anchor" href="#open-interpreter-一个会自己找办法的全能技术员" aria-label="Permalink to &quot;Open Interpreter = 一个会自己找办法的全能技术员&quot;">​</a></h3><p>给他电脑权限，他能自己摸索。</p><h3 id="cli-anything-给技术员配好的专业仪器" tabindex="-1">CLI-Anything = 给技术员配好的专业仪器 <a class="header-anchor" href="#cli-anything-给技术员配好的专业仪器" aria-label="Permalink to &quot;CLI-Anything = 给技术员配好的专业仪器&quot;">​</a></h3><p>不是瞎搞，而是用规范工具办事。</p><hr><h2 id="区别在哪" tabindex="-1">区别在哪？ <a class="header-anchor" href="#区别在哪" aria-label="Permalink to &quot;区别在哪？&quot;">​</a></h2><h3 id="open-interpreter-的优点" tabindex="-1">Open Interpreter 的优点 <a class="header-anchor" href="#open-interpreter-的优点" aria-label="Permalink to &quot;Open Interpreter 的优点&quot;">​</a></h3><ul><li>灵活</li><li>通用</li><li>上手快</li><li>什么都能试一下</li></ul><h3 id="open-interpreter-的问题" tabindex="-1">Open Interpreter 的问题 <a class="header-anchor" href="#open-interpreter-的问题" aria-label="Permalink to &quot;Open Interpreter 的问题&quot;">​</a></h3><ul><li>结果可能不稳定</li><li>经常是一堆临时操作</li><li>不容易标准化</li><li>不容易沉淀成长期可复用工具</li></ul><h3 id="cli-anything-的优点" tabindex="-1">CLI-Anything 的优点 <a class="header-anchor" href="#cli-anything-的优点" aria-label="Permalink to &quot;CLI-Anything 的优点&quot;">​</a></h3><ul><li>一旦封装好，后面很好复用</li><li>更适合自动化流水线</li><li>更适合 agent 长期调用</li><li>测试、文档、输出结构更规范</li></ul><h3 id="cli-anything-的问题" tabindex="-1">CLI-Anything 的问题 <a class="header-anchor" href="#cli-anything-的问题" aria-label="Permalink to &quot;CLI-Anything 的问题&quot;">​</a></h3><ul><li>前期改造成本高</li><li>不是立刻就能用</li><li>需要为每个软件认真做 harness</li></ul><hr><h1 id="一句话区分这四个" tabindex="-1">一句话区分这四个 <a class="header-anchor" href="#一句话区分这四个" aria-label="Permalink to &quot;一句话区分这四个&quot;">​</a></h1><p>如果你就想靠一句话分清：</p><h2 id="mcp" tabindex="-1">MCP <a class="header-anchor" href="#mcp" aria-label="Permalink to &quot;MCP&quot;">​</a></h2><p><strong>“怎么把工具接给模型”</strong></p><h2 id="browser-use" tabindex="-1">browser-use <a class="header-anchor" href="#browser-use" aria-label="Permalink to &quot;browser-use&quot;">​</a></h2><p><strong>“怎么让模型去点网页”</strong></p><h2 id="open-interpreter" tabindex="-1">Open Interpreter <a class="header-anchor" href="#open-interpreter" aria-label="Permalink to &quot;Open Interpreter&quot;">​</a></h2><p><strong>“怎么让模型直接用电脑和终端”</strong></p><h2 id="cli-anything" tabindex="-1">CLI-Anything <a class="header-anchor" href="#cli-anything" aria-label="Permalink to &quot;CLI-Anything&quot;">​</a></h2><p><strong>“怎么把软件改造成模型能稳定调用的工具”</strong></p><hr><h1 id="它们是不是可以一起用" tabindex="-1">它们是不是可以一起用？ <a class="header-anchor" href="#它们是不是可以一起用" aria-label="Permalink to &quot;它们是不是可以一起用？&quot;">​</a></h1><p>可以，而且很常见。</p><hr><h2 id="组合方式-1" tabindex="-1">组合方式 1 <a class="header-anchor" href="#组合方式-1" aria-label="Permalink to &quot;组合方式 1&quot;">​</a></h2><h3 id="cli-anything-mcp" tabindex="-1">CLI-Anything + MCP <a class="header-anchor" href="#cli-anything-mcp" aria-label="Permalink to &quot;CLI-Anything + MCP&quot;">​</a></h3><ul><li>CLI-Anything 生成工具</li><li>MCP 把工具接给模型</li></ul><p>这组合非常自然。</p><hr><h2 id="组合方式-2" tabindex="-1">组合方式 2 <a class="header-anchor" href="#组合方式-2" aria-label="Permalink to &quot;组合方式 2&quot;">​</a></h2><h3 id="open-interpreter-cli-anything" tabindex="-1">Open Interpreter + CLI-Anything <a class="header-anchor" href="#open-interpreter-cli-anything" aria-label="Permalink to &quot;Open Interpreter + CLI-Anything&quot;">​</a></h3><ul><li>Open Interpreter 负责通用执行环境</li><li>但真正调用复杂软件时，优先调用 <code>cli-anything-xxx</code></li></ul><p>这样比让 Open Interpreter 现场瞎写脚本稳得多。</p><hr><h2 id="组合方式-3" tabindex="-1">组合方式 3 <a class="header-anchor" href="#组合方式-3" aria-label="Permalink to &quot;组合方式 3&quot;">​</a></h2><h3 id="browser-use-cli-anything" tabindex="-1">browser-use + CLI-Anything <a class="header-anchor" href="#browser-use-cli-anything" aria-label="Permalink to &quot;browser-use + CLI-Anything&quot;">​</a></h3><ul><li>网页部分用 browser-use</li><li>本地软件处理部分用 CLI-Anything</li></ul><p>比如：</p><ul><li>browser-use 去网站下载素材</li><li>CLI-Anything 调 GIMP / Blender / LibreOffice 做处理</li></ul><hr><h1 id="如果从-稳定性-角度排一下" tabindex="-1">如果从“稳定性”角度排一下 <a class="header-anchor" href="#如果从-稳定性-角度排一下" aria-label="Permalink to &quot;如果从“稳定性”角度排一下&quot;">​</a></h1><p>这是个粗略感受，不是绝对真理：</p><h2 id="一般稳定性" tabindex="-1">一般稳定性 <a class="header-anchor" href="#一般稳定性" aria-label="Permalink to &quot;一般稳定性&quot;">​</a></h2><p><strong>CLI-Anything &gt; MCP（协议层，不直接比） &gt; browser-use / Open Interpreter 的临场操作</strong></p><p>更准确地说：</p><ul><li><strong>CLI-Anything</strong>：稳定在“工具层”</li><li><strong>MCP</strong>：稳定在“接入层”</li><li><strong>browser-use</strong>：灵活但容易受页面影响</li><li><strong>Open Interpreter</strong>：灵活但容易变成临时脚本杂耍</li></ul><hr><h1 id="如果从-上手快-角度排一下" tabindex="-1">如果从“上手快”角度排一下 <a class="header-anchor" href="#如果从-上手快-角度排一下" aria-label="Permalink to &quot;如果从“上手快”角度排一下&quot;">​</a></h1><p>通常是：</p><p><strong>Open Interpreter &gt; browser-use &gt; MCP 接现成工具 &gt; CLI-Anything</strong></p><p>因为 CLI-Anything 前期最重，它是“建设基础设施”的路子。</p><hr><h1 id="如果从-长期价值-角度排一下" tabindex="-1">如果从“长期价值”角度排一下 <a class="header-anchor" href="#如果从-长期价值-角度排一下" aria-label="Permalink to &quot;如果从“长期价值”角度排一下&quot;">​</a></h1><p>我会这么看：</p><h2 id="短期最快出效果" tabindex="-1">短期最快出效果 <a class="header-anchor" href="#短期最快出效果" aria-label="Permalink to &quot;短期最快出效果&quot;">​</a></h2><ul><li>Open Interpreter</li><li>browser-use</li></ul><h2 id="长期最值得沉淀" tabindex="-1">长期最值得沉淀 <a class="header-anchor" href="#长期最值得沉淀" aria-label="Permalink to &quot;长期最值得沉淀&quot;">​</a></h2><ul><li>CLI-Anything</li><li>MCP</li></ul><p>因为后两者更偏：</p><ul><li>标准化</li><li>工具化</li><li>可复用</li><li>可维护</li></ul><hr><h1 id="一个特别接地气的比喻" tabindex="-1">一个特别接地气的比喻 <a class="header-anchor" href="#一个特别接地气的比喻" aria-label="Permalink to &quot;一个特别接地气的比喻&quot;">​</a></h1><p>假设你要让 AI 帮你做报销、写报告、修图、剪视频。</p><h3 id="mcp-1" tabindex="-1">MCP <a class="header-anchor" href="#mcp-1" aria-label="Permalink to &quot;MCP&quot;">​</a></h3><p>像公司规定了： “员工可以通过统一工单系统调用工具，格式如下。”</p><h3 id="browser-use-1" tabindex="-1">browser-use <a class="header-anchor" href="#browser-use-1" aria-label="Permalink to &quot;browser-use&quot;">​</a></h3><p>像请了个会点网页的助理，帮你进系统填报销单。</p><h3 id="open-interpreter-1" tabindex="-1">Open Interpreter <a class="header-anchor" href="#open-interpreter-1" aria-label="Permalink to &quot;Open Interpreter&quot;">​</a></h3><p>像请了个电脑高手，能自己开终端、改文件、跑脚本，想到啥试啥。</p><h3 id="cli-anything-1" tabindex="-1">CLI-Anything <a class="header-anchor" href="#cli-anything-1" aria-label="Permalink to &quot;CLI-Anything&quot;">​</a></h3><p>像把一堆原本只能人工操作的软件，改造成“标准机器设备”，以后谁来都能按规范操作。</p><hr><h1 id="如果你问我该怎么选" tabindex="-1">如果你问我该怎么选 <a class="header-anchor" href="#如果你问我该怎么选" aria-label="Permalink to &quot;如果你问我该怎么选&quot;">​</a></h1><h2 id="你要-立刻能用-先把事做了" tabindex="-1">你要“立刻能用，先把事做了” <a class="header-anchor" href="#你要-立刻能用-先把事做了" aria-label="Permalink to &quot;你要“立刻能用，先把事做了”&quot;">​</a></h2><p>选：</p><ul><li><strong>Open Interpreter</strong></li><li><strong>browser-use</strong></li></ul><h2 id="你要-给模型统一接工具" tabindex="-1">你要“给模型统一接工具” <a class="header-anchor" href="#你要-给模型统一接工具" aria-label="Permalink to &quot;你要“给模型统一接工具”&quot;">​</a></h2><p>选：</p><ul><li><strong>MCP</strong></li></ul><h2 id="你要-把某类软件能力长期沉淀成稳定工具" tabindex="-1">你要“把某类软件能力长期沉淀成稳定工具” <a class="header-anchor" href="#你要-把某类软件能力长期沉淀成稳定工具" aria-label="Permalink to &quot;你要“把某类软件能力长期沉淀成稳定工具”&quot;">​</a></h2><p>选：</p><ul><li><strong>CLI-Anything</strong></li></ul><hr><h1 id="我个人的判断" tabindex="-1">我个人的判断 <a class="header-anchor" href="#我个人的判断" aria-label="Permalink to &quot;我个人的判断&quot;">​</a></h1><p>我觉得这几个东西不是替代关系，而是不同层次：</p><ul><li><strong>browser-use</strong>：前台网页操作层</li><li><strong>Open Interpreter</strong>：通用执行层</li><li><strong>CLI-Anything</strong>：专用工具构建层</li><li><strong>MCP</strong>：工具接入协议层</li></ul><p>如果真要做一个靠谱的 agent 系统，最后多半不是四选一，反而是混搭：</p><ul><li>用 <strong>Open Interpreter</strong> 兜底</li><li>用 <strong>browser-use</strong> 处理网页</li><li>用 <strong>CLI-Anything</strong> 沉淀高价值软件能力</li><li>用 <strong>MCP</strong> 统一把这些工具接给模型</li></ul><p>这个组合其实挺合理。</p>`,187)])])}const c=a(n,[["render",l]]);export{g as __pageData,c as default};
